int main(int argc, char *argv[])

{

  for(;;) {

    int n;

    cin >> n;

    if(n==0) break;

    string sa, sb;

    getline(cin, sa);

    getline(cin, sa);

    getline(cin, sb);

    auto conv = [n](string &s) {

      int r = 0;

      for(int i = 0; i < n; i++) {

        r = (r<<1) + (s[i] == 'W' ? 1 : 0); 

      }

      return r;

    };

    int a = conv(sa);

    int b = conv(sb);

    //cout << "a = " << static_cast<std::bitset<8> >(a) << endl;

    //cout << "b = " << static_cast<std::bitset<8> >(b) << endl;



    // state = (pos, panels)

